Checked Func:
pub const fn into_inner(pin: Pin<Ptr>) -> Ptr {
    pin.pointer
}

Unchecked Func:
pub const unsafe fn new_unchecked(pointer: Ptr) -> Pin<Ptr> {
    Pin { pointer }
}

